-- supabase/migrations/034_apro_license_catalog.sql
--
-- Apro-Lizenz-Katalog: Hersteller "Apro", Kategorie "Apro-Lizenz",
-- 53 Lizenz-Modelle aus docs/data/apro-lizenzen.xlsx mit EK/VK
-- (einmalig) + EK/VK Softwarepflege (monatlich).
--
-- Erweitert models um drei nullable Spalten:
--   notes (text)                                  - freier Hinweis am Modell
--   default_monthly_update_fee_ek (numeric(10,2)) - monatliche EK-Pflege
--   default_monthly_update_fee_vk (numeric(10,2)) - monatliche VK-Pflege
--
-- Idempotent. Re-Run via NOT EXISTS (UNIQUE-Index auf models enthält
-- nullable version, ON CONFLICT würde Duplikate erlauben).

-- 1) Schema-Erweiterung -------------------------------------------------------
ALTER TABLE models
  ADD COLUMN IF NOT EXISTS notes text,
  ADD COLUMN IF NOT EXISTS default_monthly_update_fee_ek numeric(10,2),
  ADD COLUMN IF NOT EXISTS default_monthly_update_fee_vk numeric(10,2);

-- 2) Hersteller "Apro" --------------------------------------------------------
VALUES ('Apro')
ON CONFLICT (name) DO NOTHING;

-- 3) Kategorie "Apro-Lizenz" --------------------------------------------------
VALUES ('Apro-Lizenz', 'key-round', 'generic', 'sonstiges')
ON CONFLICT (name) DO NOTHING;

-- 4) Lizenz-Modelle seeden ----------------------------------------------------
-- 53 Lizenz-Zeilen aus apro-lizenzen.xlsx

NOTIFY pgrst, 'reload schema';
